    try {
        const { data } = await HostelApi.post('/login', form_data)
        return data;
    } catch (error) {
        return false
    }
}

//////////////////////////////////////////////////////////

export const HostelAuthApi = async (token) => {
    try {
        const { data } = await HostelApi.post('/auth', {}, { headers: { "hosteltoken": token } })
        return data;
    } catch (error) {
        return false
    }
}

